// ─── ECHO CORRECTIONS ────────────────────────────────────────────────────────
// Top 20 Thai learner mistakes. Fixed silently, never "you're wrong."

export const ECHO_CORRECTIONS: Record<string, string> = {
  "I am go": "I go",
  "I am want": "I want",
  "she is go": "she goes",
  "very very": "really",
  "I no like": "I don't like",
  "I not like": "I don't like",
  "he no have": "he doesn't have",
  "I am boring": "I am bored",
  "I am interesting": "I am interested",
  "can to go": "can go",
  "I am agree": "I agree",
  "finish already": "already finished",
  "same same": "the same",
  "up to you": "it's up to you",
  "mai pen rai": "never mind",
};

