// ─── SESSION SUMMARY TEMPLATES ────────────────────────────────────────────────
// End of session. Template filled by session engine. Never AI generated.

export const sessionSummary = (words: string[], exchanges: number) => ({
  th: `วันนี้คุณเรียนรู้ ${words.length} คำใหม่ค่า~ ${words.map((w) => `'${w}'`).join(", ")} และคุยกับหนูไป ${exchanges} ครั้งแล้วนะคะ~ เก่งมากค่า~`,
  en: `Today you learned ${words.length} new word${words.length !== 1 ? "s" : ""}: ${words.join(", ")}. You had ${exchanges} exchanges with me~ Amazing work~`,
});

